<script>
import { mapState } from "vuex";
export default {
  name: "RemoteController",

  data: function () {
    return {
      showKeyBlade: false,
      lastClick: Date.now(),
    };
  },

  computed: {
    ...mapState("hud", ["remoteController"]),
  },

  methods: {
    setKeyBlade: function () {
      this.showKeyBlade = !this.showKeyBlade;
    },
    buttonClick: function (buttonName) {
      if (this.lastClick + 1000 > Date.now()) return;
      this.lastClick = Date.now();
      switch (buttonName) {
        case "bibi":
          window.mp.triggerServer(
            "vehicle::key::changeSignal",
            this.remoteController.vehicleId
          );
          break;
        case "gps":
          window.mp.triggerServer(
            "vehicle::key::enableGPS",
            this.remoteController.vehicleId
          );
          break;
        case "evacuation":
          window.mp.triggerServer(
            "vehicle::key::evacCar",
            this.remoteController.vehicleId
          );
          break;
        case "engine":
          window.mp.triggerServer(
            "vehicle::key::changeEngine",
            this.remoteController.vehicleId
          );
          break;
        case "signalization":
          window.mp.triggerServer(
            "vehicle::key::changeSignaling",
            this.remoteController.vehicleId
          );
          break;
        case "centralLock":
          window.mp.triggerServer(
            "vehicle::key::lockCar",
            this.remoteController.vehicleId
          );
          break;
      }
    },
    doorStateChange: function (doorIndex) {
      if (this.lastClick + 1000 > Date.now()) return;
      this.lastClick = Date.now();
      window.mp.triggerServer(
        "vehicle::key::changeDoorState",
        this.remoteController.vehicleId,
        doorIndex
      );
    },
  },
};
</script>

